import sys
from collections import defaultdict

def parse_input(filename):
    with open(filename) as f:
        content = f.read()

    all_lines = content.strip().split('\n')

    shapes = []
    regions = []

    current_shape_idx = None
    current_shape_lines = []

    i = 0
    while i < len(all_lines):
        line = all_lines[i]
        stripped = line.strip()

        # Check if it's a shape header like "0:"
        if stripped.endswith(':') and stripped[:-1].isdigit():
            if current_shape_idx is not None and current_shape_lines:
                shapes.append(parse_shape(current_shape_lines))
            current_shape_idx = int(stripped[:-1])
            current_shape_lines = []
            i += 1
        elif 'x' in stripped and ':' in stripped and not set(stripped.split(':')[0]) <= {'#', '.', ' '}:
            # This is a region line - shapes section ended
            if current_shape_idx is not None and current_shape_lines:
                shapes.append(parse_shape(current_shape_lines))
                current_shape_idx = None
                current_shape_lines = []
            parse_region_line(stripped, regions)
            i += 1
        elif current_shape_idx is not None and stripped and all(c in '#.' for c in stripped):
            current_shape_lines.append(stripped)
            i += 1
        elif current_shape_idx is not None and not stripped:
            # blank line - might separate shapes
            i += 1
        else:
            i += 1

    if current_shape_idx is not None and current_shape_lines:
        shapes.append(parse_shape(current_shape_lines))

    return shapes, regions

def parse_shape(lines):
    cells = set()
    for r, line in enumerate(lines):
        for c, ch in enumerate(line):
            if ch == '#':
                cells.add((r, c))
    return frozenset(cells)

def parse_region_line(line, regions):
    colon_idx = line.index(':')
    dims = line[:colon_idx].strip()
    counts_str = line[colon_idx+1:].strip()

    w, h = dims.split('x')
    width, height = int(w), int(h)
    counts = list(map(int, counts_str.split()))
    regions.append((width, height, counts))

def normalize_shape(cells):
    """Normalize a shape so its top-left is at (0,0)"""
    if not cells:
        return frozenset()
    min_r = min(r for r, c in cells)
    min_c = min(c for r, c in cells)
    return frozenset((r - min_r, c - min_c) for r, c in cells)

def get_orientations(shape):
    """Get all unique orientations (rotations + flips) of a shape"""
    cells = list(shape)
    orientations = set()

    current = cells
    for _ in range(4):
        norm = normalize_shape(current)
        orientations.add(norm)
        flipped = normalize_shape([(r, -c) for r, c in norm])
        orientations.add(flipped)
        current = [(c, -r) for r, c in current]

    return list(orientations)

def get_all_placements(shape_cells, width, height):
    """Get all valid placements of a shape as frozensets of (r,c) cell positions"""
    orientations = get_orientations(shape_cells)
    placements = set()

    for orient in orientations:
        cells = list(orient)
        max_r = max(r for r, c in cells)
        max_c = max(c for r, c in cells)

        for dr in range(height - max_r):
            for dc in range(width - max_c):
                placed = frozenset((r + dr, c + dc) for r, c in cells)
                placements.add(placed)

    return list(placements)

# Dancing Links (DLX) implementation for exact cover
# We model this as: 
#   Columns = grid cells (one per cell) + piece-type columns
#   Rows = each possible placement of each piece instance
# 
# However with large grids this is huge. Let's use a simpler 
# backtracking with smart pruning.

def can_fit(width, height, present_list, shape_placements):
    """
    Try to fit all presents in a width x height region.
    present_list: list of shape indices (with repetition)
    shape_placements: dict idx -> list of frozensets

    Uses backtracking with:
    1. Place pieces one by one
    2. Always place the piece that covers the "first free cell" 
       (leftmost topmost) - this prunes the search drastically
    """
    if not present_list:
        return True

    total_cells_needed = sum(len(next(iter(shape_placements[idx]))) for idx in present_list)
    if total_cells_needed > width * height:
        return False

    # Build a lookup: for each piece type, which placements cover each cell?
    # cell_placements[idx][cell] = list of placement indices

    # For efficiency, precompute: for each shape idx, placements as list of frozensets
    # and for each shape idx, a dict: cell -> list of placements containing that cell

    cell_to_placements = {}  # (shape_idx, cell) -> list of frozensets
    for idx in set(present_list):
        for p in shape_placements[idx]:
            for cell in p:
                key = (idx, cell)
                if key not in cell_to_placements:
                    cell_to_placements[key] = []
                cell_to_placements[key].append(p)

    # Backtracking: track which piece instances remain
    # Use multiset representation: dict of idx -> count
    from collections import Counter
    remaining_counts = Counter(present_list)

    def find_first_free(occupied):
        for r in range(height):
            for c in range(width):
                if (r, c) not in occupied:
                    return (r, c)
        return None

    def backtrack(occupied, remaining_counts):
        # Find first free cell
        cell = find_first_free(occupied)
        if cell is None:
            return not any(remaining_counts.values())

        # Try to cover this cell with some remaining piece
        for idx in list(remaining_counts.keys()):
            if remaining_counts[idx] == 0:
                continue

            # Get placements of shape idx that cover this cell
            placements_for_cell = cell_to_placements.get((idx, cell), [])

            for placement in placements_for_cell:
                # Check if placement is valid (no overlap)
                if not (placement & occupied):
                    remaining_counts[idx] -= 1
                    if remaining_counts[idx] == 0:
                        del remaining_counts[idx]

                    result = backtrack(occupied | placement, remaining_counts)

                    if idx not in remaining_counts:
                        remaining_counts[idx] = 0
                    remaining_counts[idx] += 1
                    if remaining_counts[idx] == 0:
                        del remaining_counts[idx]

                    if result:
                        return True

        return False

    return backtrack(frozenset(), remaining_counts)


def solve(filename):
    shapes, regions = parse_input(filename)

    # Pre-verify parsing
    sys.stderr.write(f"Parsed {len(shapes)} shapes, {len(regions)} regions\n")

    count = 0

    for region_idx, (width, height, counts) in enumerate(regions):
        # Build list of presents needed
        present_list = []
        for shape_idx, cnt in enumerate(counts):
            present_list.extend([shape_idx] * cnt)

        if not present_list:
            count += 1
            continue

        # Cache placements for each unique shape index needed
        shape_placements = {}
        for shape_idx in set(present_list):
            shape_placements[shape_idx] = get_all_placements(shapes[shape_idx], width, height)

        result = can_fit(width, height, present_list, shape_placements)
        if result:
            count += 1

        if region_idx % 10 == 0:
            sys.stderr.write(f"  Region {region_idx}/{len(regions)}: {width}x{height}, {len(present_list)} pieces -> {result}\n")

    return count

